#include <iostream>

class Point {
private:
    int x;
    int y;

public:
    Point() : x(0), y(0) {}
    Point(int x_val, int y_val) : x(x_val), y(y_val) {}
    Point(const Point& other) : x(other.x), y(other.y) { std::cout << "Copy constructor called. Point(" << x << ", " << y << ") copied from (" << other.x << ", " << other.y << ")" << std::endl; }
    int getX() const { return x; }
    int getY() const { return y; }
    void display() const { std::cout << "Point coordinates: (" << x << ", " << y << ")" << std::endl; }
};

void processPoint(Point p) { std::cout << "Inside processPoint function.\n"; p.display(); }

int main() {
    Point p1(10, 20);
    std::cout << "Original p1: "; p1.display();
    std::cout << "Initializing p2 from p1:\n"; Point p2 = p1;
    std::cout << "Copied p2: "; p2.display();
    std::cout << "Passing p1 to function:\n"; processPoint(p1);
    return 0;
}
